script.xsl:text:
							/////////////////////////////////////////////////////
//
//
var EVALUADOR;
var EVALUADORES = new Object();            

EVALUADORES.items=new Array();           
EVALUADORES.Add = function(EVALUADOR) { this.items["K"+EVALUADOR.oi_personal_emp]=EVALUADOR; };
EVALUADORES.Get = function(oi_personal_emp) { return this.items["K"+oi_personal_emp]; };

							/////////////////////////////////////////////////////
//
//
var ESCALAS = new Object();            

ESCALAS.items=new Array();
ESCALAS.Add = function(ESCALA) { this.items["K"+ESCALA.oi_escala]=ESCALA; }
ESCALAS.Get = function(oi_escala) { return this.items["K"+oi_escala]; }

var ESCALA, ESCVAL;

							/////////////////////////////////////////////////////
//
//   

function PlantillaBase(pID)
{               
	this.Count=0;                
	this.Id=pID;
	this.Escala=0;
	this.Pond=1.0;
	this.Decimales=0;     
	this.PondDecimales=0;  

	//Estados	
	this.Show=0;
	this.Edit=0;
	this.Evaluador=0;
	this.Evaluador360=0;
	this.Evaluado=0;
	this.Supervisor=0;
	this.Comentarios=0;
	this.MostrarResumen=0;  

	//Permite
	this.SumEva=0;
	this.SumAut=0;
	this.SumSup=0;
	this.Sum360=0;      

 	//Valores
	this.Value1=null;
	this.Value2=null;
	this.Value3=null;              
	this.Values=new Array();

	//Elementos Hijos
	this.Items=new Array();          

	//Funciones para ITEMS
	this.AddItem = function(IT) { this.Items["K_"+IT.Id]=IT; }       
	this.GetItem = function(ITID) { return this.Items["K_"+ITID]; }       
	this.DelItem = function(Id)
	{              
		if (!confirm("Esta seguro que quiere Eliminarlo?")) return;

		var MyIT=this.GetItem(Id);
		MyIT.Delete=true;  

		//Elimino los ROWS HIJOS
		for (key in MyIT.Subitems)
		{
			var MySUBITEM=MyIT.Subitems[key];
			if (!MySUBITEM.Delete)
			this.DelSubitem(Id,MySUBITEM.Id,true);
		}                                

	  var MyTR;
		var TBL=document.getElementById("TBL_"+this.Id);
		if (TBL)
		{
			//Elimino el ROW
			MyTR=document.getElementById("TR_O_"+Id);
			if (MyTR) TBL.deleteRow(MyTR.rowIndex);

			//Elimino el ROWADD
			MyTR=document.getElementById("TR_OA_"+Id);
			if (MyTR) TBL.deleteRow(MyTR.rowIndex);

			//Elimino el ROW SUBTOTAL
			MyTR=document.getElementById("TR_OR_"+Id);
			if (MyTR) TBL.deleteRow(MyTR.rowIndex);

			//Elimino el ROW SUBTOTAL
			MyTR=document.getElementById("TR_ST_"+Id);
			if (MyTR) TBL.deleteRow(MyTR.rowIndex);
		}

		this.RECALC();
		this.REFRESH();
	}                     
	this.NewItem = function()
	{              
		this.Count++;        

		var ITEM=new Object();  
		ITEM.Id="N_"+this.Id+"_"+this.Count;
		ITEM.Pond=1;
		ITEM.Escala=this.Escala;
		ITEM.Values=new Array();	
		ITEM.Value1=null;
		ITEM.Value2=null;
		ITEM.Value3=null;
		ITEM.Cus1="";
		ITEM.Cus2="";
		ITEM.Cus3="";
		ITEM.Cus4="";
		ITEM.Cus5="";
		ITEM.New=true;
		ITEM.Delete=false;
		ITEM.Subitems=new Array();
		this.AddItem(ITEM);

		//Cargos los TRS
		var arr_TR_TMP=new Array();
		var TR_TMP;
		for (var i=0; i!=4; i++)
		{
			switch(i)
			{
				case 0: TR_TMP=document.getElementById("TR_OT_"+this.Id); break;
				case 1: TR_TMP=document.getElementById("TR_OTA_"+this.Id); break;
				case 2: TR_TMP=document.getElementById("TR_OTR_"+this.Id); break;
				case 3: TR_TMP=document.getElementById("TR_STT_"+this.Id); break;
			}        
			if (TR_TMP) arr_TR_TMP.push(TR_TMP);
		}

		var TBL=document.getElementById("TBL_"+this.Id);

		//Agrego los ROWs
		if (TBL)
		for (var i=0; i!=arr_TR_TMP.length; i++)
		{
			var TBL=document.getElementById("TBL_"+this.Id);
			var TR_TMP=arr_TR_TMP[i];

			var TR=TBL.insertRow(TBL.rows.length-1-arr_TR_TMP.length);
			TR.className=TR_TMP.className;

			switch(i)
			{
				case 0: TR.id="TR_O_"+ITEM.Id; break;
				case 1: TR.id="TR_OA_"+ITEM.Id; break;
				case 2: TR.id="TR_OR_"+ITEM.Id; break;
				case 3: TR.id="TR_ST_"+ITEM.Id; TR.style.display="none"; break;
			}


			for (var t=0; t!=TR_TMP.cells.length; t++)
			{                 
				var CELD=TR.insertCell(-1);

				strHTML=TR_TMP.cells.item(t).innerHTML;
				strHTML=Replace(strHTML,"STR_REPLACE_NAME","'"+ITEM.Id+"'");
				strHTML=Replace(strHTML,"REPLACE_NAME",ITEM.Id);
				strHTML=Replace(strHTML,"REPLACE_X_NAME","REPLACE_NAME");

				CELD.innerHTML=strHTML;
				CELD.className=TR_TMP.cells.item(t).className;
			}
		}          

		this.RECALC();
		this.REFRESH();
	}


	//Funciones para SUBITEMS
	this.AddSubitem = function(ITID, SIT) { this.Items["K_"+ITID].Subitems["K_"+SIT.Id]=SIT; }       
	this.GetSubitem = function(ITID, SITID) { return this.Items["K_"+ITID].Subitems["K_"+SITID]; }   
	this.DelSubitem = function(ItemID, SubitemID, force)
	{                                                 
		if (force?false:true) if (!confirm("Esta seguro que quiere Eliminarlo?")) return;

		var MyIT=this.GetSubitem(ItemID, SubitemID);
		MyIT.Delete=true;  

		//Elimino el ROW
		var TBL=document.getElementById("TBL_"+this.Id);
		if (TBL)
		{
			var MyTR=document.getElementById("TR_S_"+ItemID+"_"+SubitemID);
			if (MyTR) TBL.deleteRow(MyTR.rowIndex);
		}

		if (force?false:true)
		{                     
			this.RECALC();
			this.REFRESH();
		}
	}       
	this.NewSubitem = function(ItemId)
	{              
		this.Count++;             

		var ITEM=this.GetItem(ItemId);

		var SUBITEM=new Object();  
		SUBITEM.Id=ItemId+"_N_"+this.Count;
		SUBITEM.Pond=1;
		SUBITEM.Escala=this.Escala;
		SUBITEM.Values=new Array();	
		SUBITEM.Value1=null;
		SUBITEM.Value2=null;
		SUBITEM.Value3=null;
		SUBITEM.New=true;
		SUBITEM.Delete=false;
		this.AddSubitem(ItemId,SUBITEM);

		var rowIndex=document.getElementById("TR_OA_"+ItemId).rowIndex;

		//Agrego los ROWs
		var TBL=document.getElementById("TBL_"+this.Id);
		var TR_TMP=document.getElementById("TR_ST_"+ItemId);

		var TR=TBL.insertRow(rowIndex);
		TR.className=TR_TMP.className;
		TR.id="TR_S_"+ItemId+"_"+SUBITEM.Id;

		for (var t=0; t!=TR_TMP.cells.length; t++)
		{                 
			var CELD=TR.insertCell(-1);

			strHTML=TR_TMP.cells.item(t).innerHTML;
			strHTML=Replace(strHTML,"STR_REPLACE_NAME","'"+SUBITEM.Id+"'");
			strHTML=Replace(strHTML,"REPLACE_NAME",SUBITEM.Id);
			strHTML=Replace(strHTML,"REPLACE_X_NAME","REPLACE_NAME");

			CELD.innerHTML=strHTML;
			CELD.className=TR_TMP.cells.item(t).className;
		}

		this.RECALC();
		this.REFRESH();
	}


	this.RECALC = function()
	{                
		this.OK=true;   
	}

	this.REFRESH = function()
	{
		var MyITEM, CELD, key;
		if (this.Show!='1') return;

		//Totales ITEMS
		for (key in this.Items)
		{
			MyITEM=this.Items[key];
			if (MyITEM.Delete) continue;

			CELD=document.getElementById("TE_"+this.Id+"_"+MyITEM.Id);
			if (CELD) CELD.innerHTML=FormatTotal(MyITEM.Escala, MyITEM.Value1, this.Decimales);

			CELD=document.getElementById("TA_"+this.Id+"_"+MyITEM.Id);
			if (CELD) CELD.innerHTML=FormatTotal(MyITEM.Escala, MyITEM.Value2, this.Decimales);

			CELD=document.getElementById("TS_"+this.Id+"_"+MyITEM.Id);
			if (CELD) CELD.innerHTML=FormatTotal(MyITEM.Escala, MyITEM.Value3, this.Decimales);

			if (this.Evaluador360=='2')
			{  
				for (key in EVALUADORES.items)
				{
					CELD=document.getElementById("T3_"+this.Id+"_"+MyITEM.Id+"_"+key.substr(1));
					if (CELD) CELD.innerHTML=FormatTotal(MyITEM.Escala, MyITEM.Values[key], this.Decimales);
				}
			} else
			{
				CELD=document.getElementById("T3_"+this.Id+"_"+MyITEM.Id+"_"+EVALUADORES.oi_evaluador_360);
				if (CELD) CELD.innerHTML=FormatTotal(MyITEM.Escala, MyITEM.Values["K"+EVALUADORES.oi_evaluador_360], this.Decimales);
			}
		}

	  //Totales Plantilla
		CELD=document.getElementById("TE_"+this.Id);
		if (CELD) CELD.innerHTML=FormatTotal(this.Escala, this.Value1, this.Decimales);

		CELD=document.getElementById("TA_"+this.Id);
		if (CELD) CELD.innerHTML=FormatTotal(this.Escala, this.Value2, this.Decimales);

		CELD=document.getElementById("TS_"+this.Id);
		if (CELD) CELD.innerHTML=FormatTotal(this.Escala, this.Value3, this.Decimales);

		if (this.Evaluador360=='2')
		{       
			for (key in EVALUADORES.items)
			{
				CELD=document.getElementById("T3_"+this.Id+"_"+key.substr(1));
				if (CELD) CELD.innerHTML=FormatTotal(this.Escala, this.Values[key], this.Decimales);
			}
		} else
		{
			CELD=document.getElementById("T3_"+this.Id+"_"+EVALUADORES.oi_evaluador_360);
			if (CELD) CELD.innerHTML=FormatTotal(this.Escala, this.Values["K"+EVALUADORES.oi_evaluador_360], this.Decimales);
		}

		//Cambios Especiales
		this.REFRESH_ADIC();
	}


	this.DDOCHANGE = function(DDOEVA, DDOPLA)
	{               
		if (this.Show!='1') return;
		DDOPLA.SetAttr("nmd-status" , "~u,");

		//Cambios Basicos
		if (this.Evaluador =="2") DDOPLA.SetAttr("n_resultado" , this.Value1==null?"":this.Value1);
		if (this.Evaluado  =="2") DDOPLA.SetAttr("n_resultado2", this.Value2==null?"":this.Value2);
		if (this.Supervisor=="2") DDOPLA.SetAttr("n_resultado3", this.Value3==null?"":this.Value3);

		//Comentarios de la Plantilla
		if (this.Comentarios=='2')                                                 
		{
			var COMENT=document.getElementById("COMMENT_"+this.Id);
			if (COMENT)
			{              
				CheckSize("COMENT",4000,COMENT);
				DDOPLA.SetAttr("nmd-status"  , "~u,");
				DDOPLA.SetAttr("n_resultado" , "");
				DDOPLA.SetAttr("n_resultado2", "");
				DDOPLA.SetAttr("n_resultado3", "");
				DDOPLA.SetAttr("o_plantilla" , COMENT.value);
			}
		}    

		//Cambios Especiales
		this.DDOCHANGE_ADIC(DDOEVA, DDOPLA);
	}                   

	this.DDOCHANGE_ADIC=function() {	}
	this.REFRESH_ADIC=function() {	}

	EVA.AddPlantilla(this);
}



var EVA=new Object();
EVA.Values=new Array();
EVA.Plantillas=new Array();

							EVA.AddPlantilla = function(MyOBJ)
{                
	this.Plantillas["K_"+MyOBJ.Id]=MyOBJ;
}

EVA.GetPlantilla = function(Id)
{                
	return this.Plantillas["K_"+Id];
}

function compare(V1, V2)
{
	var DIF=V2-V1;
	if (DIF==0) return 0;
	if (Math.abs(DIF)==DIF) return -1;

	return 1;
}

function Replace(strin, strfnd, strrpl) 
{
	return strin.replace(new RegExp(strfnd, "ig"), strrpl);
}   

function GetNumber(num,dec) 
{              
	var fnum=parseFloat(Replace(num.toString(),',','.'));
	if (isNaN(fnum))  
	{ 
		switch(num.toString().toUpperCase())
		{             
			case "NA":
			case "N/A":
			case "NO":
			case "NO APLICA":
				return -1;

			default:
				return null;
		}

	} else
		return Number(fnum).toFixed(dec);
}           

function FormatNumber(num, dec) 
{              
	var value=Replace(""+num,',','.');
	if (isNaN(value)) return "";

	if (compare(num,0)==-1) return "N/A";

	//Genero el valor
	for (var t=0; t!=dec; t++) value=value*10;
	value=Math.round(value).toString();

	//Agrego los Ceros faltantes                                      
	while(compare(value.length,1+dec)==-1) value="0"+value;

	if (dec!=0)
	value=value.substr(0,value.length-dec)+"."+value.substr(value.length-dec);

	//Resultado
	return value;
}     

function FormatTotal(oi_escala, valor, dec)
{
	var t;
	var ESCALA=ESCALAS.Get(oi_escala);     

	//Verifico el VACIO
	if (isNaN(valor)) return "";
	if (valor==null) return "";

	//Calculo el VALOR
	if (ESCALA.Valores.length==0)
	{ //Continuo de 0 a 100
		if (compare(valor,0)==-1)
			return "N/A";
		else
			return FormatNumber(valor,dec)+"%";
	} else                       
	if (ESCALA.Valores.length==1)
	{ //Continuo de min a max
		if (compare(valor,0)==-1)
			return "N/A";
		else
			return FormatNumber(valor,dec)+"/"+FormatNumber(ESCALA.max,dec);
	} else
	{ //Busco la Enumeracion
		for (t=0; compare(t,ESCALA.Valores.length-1)!=1; t++)
		{
			ESCVAL=ESCALA.Valores[t];
			if (compare(valor,ESCVAL.max)!=1)
				if (compare(valor,ESCVAL.min)==1)
				{
					if (compare(valor,0)==-1)
						return ESCVAL.des;
					else
						return ESCVAL.des+" ("+FormatNumber(valor,dec)+"/"+FormatNumber(ESCALA.max,dec)+")";
				}
		}  

		if (compare(valor,0)==-1)
			return "N/A";
		else
			return "? ("+FormatNumber(valor,dec)+"/"+FormatNumber(ESCALA.max,dec)+")";
	}

	return retval;
}


function ShowTooltip(obj)
{                       
	var xxx=obj.getElementsByTagName("div");
	if (xxx)
	if (xxx.length!=0)
	if (xxx[0].className=="tooltip")  
	{
		xxx[0].style.display="block";
		xxx[0].style.opacity=1; 
	}
}
function HideTooltip(obj)
{
	var xxx=obj.getElementsByTagName("div");
	if (xxx)
	if (xxx.length!=0)           
	if (xxx[0].className=="tooltip")     
	{	
		xxx[0].style.opacity=0;
		xxx[0].style.display="none";
	}
}          


var objERR;
function CallbackError() { objERR.focus(); }

function ThrowError(MSG, OBJ)
{         
	objERR=OBJ;  
	MyPARAM=new Array(); MyPARAM[0]=""; MyPARAM[1]=""; MyPARAM[2]=""; MyPARAM[3]=""; MyPARAM[4]=""; MyPARAM[5]=""; MyPARAM[6]=""; MyPARAM[7]=""; MyPARAM[8]=""; MyPARAM[9]="";
	parent.ClientThrowErrorArr(MSG, MyPARAM, CallbackError);
}                                     

function CheckSize(tipe, size, OBJ)
{                                 
	if (compare(OBJ.value.length,size)==1)
		ThrowError("EDD.EVA."+tipe, OBJ);
}


function IsComplete()
{  
	var key;          
	for(key in EVA.Plantillas)
		if (EVA.Plantillas[key].Show=='1')
			if (!(EVA.Plantillas[key].OK))
				return false;

	return true;                  
}

function REFRESH()
{ 
	var key, MyPLA;
	if (parent.set_report_window)
		parent.set_report_window(window);

	/////////////////////////////////////////////////////
	//Realizando los Calculos individuales   
	for(key in EVA.Plantillas)
	{                 
		MyPLA=EVA.Plantillas[key];
		MyPLA.RECALC();
	}

	/////////////////////////////////////////////////////
	//Calculando Totales
	EVA.Value1  =0.0;
	EVA.Value2  =0.0;
	EVA.Value3  =0.0;
	EVA.Values["K"+EVALUADORES.oi_evaluador_360]=0.0;
	EVA.MaxValue1=0.0;
	EVA.MaxValue2=0.0;
	EVA.MaxValue3=0.0;
	EVA.MaxValues=0.0;

	for(key in EVA.Plantillas)
	{
		MyPLA=EVA.Plantillas[key];
		if (!MyPLA.MostrarResumen) continue;

		//Recalcula los Valores
		MyPLA.RECALC();

		//Calculo del Valores
		escMax=ESCALAS.Get(MyPLA.Escala).max;

		if (MyPLA.SumEva) 
		{                 
			if (MyPLA.Value1==null || EVA.Value1==null) 
				EVA.Value1 =null;
			else
			if (compare(MyPLA.Value1,0)!=-1)         
			{
				EVA.MaxValue1+=MyPLA.Pond;
				EVA.Value1+=MyPLA.Pond*MyPLA.Value1/escMax;
			}
		}                 
		if (MyPLA.SumAut)  
		{
			if (MyPLA.Value2==null || EVA.Value2==null) 
				EVA.Value2 =null;
			else
			if (compare(MyPLA.Value2,0)!=-1)         
			{
				EVA.MaxValue2+=MyPLA.Pond;
				EVA.Value2+=MyPLA.Pond*MyPLA.Value2/escMax;
			}
		}                 
		if (MyPLA.SumSup)  
		{
			if (MyPLA.Value3==null || EVA.Value3==null) 
				EVA.Value3=null;
			else
			if (compare(MyPLA.Value3,0)!=-1)         
			{
				EVA.MaxValue3+=MyPLA.Pond;
				EVA.Value3+=MyPLA.Pond*MyPLA.Value3/escMax;
			}
		}                 

		if (MyPLA.Sum360)  
		if (MyPLA.Values)
		{

			if (MyPLA.Values["K"+EVALUADORES.oi_evaluador_360]==null || EVA.Values["K"+EVALUADORES.oi_evaluador_360]==null) 
				EVA.Values["K"+EVALUADORES.oi_evaluador_360] =null;
			else
			if (compare(MyPLA.Values["K"+EVALUADORES.oi_evaluador_360],0)!=-1)         
			{
				EVA.MaxValues+=MyPLA.Pond;
				EVA.Values["K"+EVALUADORES.oi_evaluador_360]+=MyPLA.Pond*MyPLA.Values["K"+EVALUADORES.oi_evaluador_360]/escMax;
			}
		}                 
	}                                 

 	if (EVA.Value1!=null)
 	{
 		if (compare(EVA.Value1,0)==-1 || EVA.MaxValue1==0.0) EVA.Value1=-1; else EVA.Value1=EVA.Value1/EVA.MaxValue1*ESCALAS.Get(EVA.Escala).max;
 	}
 	if (EVA.Value2!=null)
 	{
 		if (compare(EVA.Value2,0)==-1 || EVA.MaxValue2==0.0) EVA.Value2=-1; else EVA.Value2=EVA.Value2/EVA.MaxValue2*ESCALAS.Get(EVA.Escala).max;
 	}
 	if (EVA.Value3!=null)
 	{
 		if (compare(EVA.Value3,0)==-1 || EVA.MaxValue3==0.0) EVA.Value3=-1; else EVA.Value3=EVA.Value3/EVA.MaxValue3*ESCALAS.Get(EVA.Escala).max;
 	}
 	if (EVA.Values["K"+EVALUADORES.oi_evaluador_360]!=null || EVA.MaxValues==0.0)
 	{
 		if (compare(EVA.Values["K"+EVALUADORES.oi_evaluador_360],0)==-1) EVA.Values["K"+EVALUADORES.oi_evaluador_360]=-1; else EVA.Values["K"+EVALUADORES.oi_evaluador_360]=EVA.Values["K"+EVALUADORES.oi_evaluador_360]/EVA.MaxValues*ESCALAS.Get(EVA.Escala).max;
 	}



	/////////////////////////////////////////////////////
  //Actualizar HTML   
	for(key in EVA.Plantillas)
	{                              
		MyPLA=EVA.Plantillas[key];
		MyPLA.REFRESH();
	}
}

function DDOCHANGE(DDOEVA)
{
	var key, MyPLA, DDO360, CUR;

	DDOEVA.SetAttr("nmd-status","~u,");


	/////////////////////////////////////////////////////
	//Realizando los Calculos individuales   
	for(key in EVA.Plantillas)
	{
		MyPLA=EVA.Plantillas[key];
		MyPLA.DDOCHANGE(DDOEVA, DDOEVA.FindElement("PLANTILLAS").FindElement2("PLANTILLA","ID",MyPLA.Id));
	}

	DDOEVA.SetAttr("n_resultado" , (EVA.Value1==null?"":EVA.Value1)); 
	DDOEVA.SetAttr("n_resultado2", (EVA.Value2==null?"":EVA.Value2)); 
	DDOEVA.SetAttr("n_resultado3", (EVA.Value3==null?"":EVA.Value3)); 

	/////////////////////////////////////////////////////
	//TOTAL 360
	DDO360=null;
	for (CUR=DDOEVA.FindElement("EVALUADORES").FirstChild(); CUR!=null; CUR=CUR.Next())
		if (CUR.FindElement("oi_personal_emp").GetAttr("value")==EVALUADORES.oi_evaluador_360)
		{
			DDO360=CUR;
			break;
		}      

	if (DDO360!=null)     
	{
		DDO360.SetAttr("nmd-status","~u,");                             
		DDO360.SetAttr("n_resultado", (EVA.Values["K"+EVALUADORES.oi_evaluador_360]==null?"":EVA.Values["K"+EVALUADORES.oi_evaluador_360])); 

		if (DDO360.GetAttr("c_estado")=="I" || DDO360.GetAttr("c_estado")=="C")
			DDO360.SetAttr("c_estado", EVA.Values["K"+EVALUADORES.oi_evaluador_360]==null?"I":"C");
	}
};

					PLA.RECALC = function()
{    
	if (this.Show!='1') return;

	var key, MyITEM, t, found=false;   

	this.Value1=0.0;
	this.Value2=0.0;
	this.Value3=0.0;
	this.MaxValue1=0.0;
	this.MaxValue2=0.0;
	this.MaxValue3=0.0;
	this.OK=true;

	//Recorro los ITEMS
	for (key in this.Items)
	{
		MyITEM=this.Items[key];
		if (MyITEM.Delete) continue;
		found=true;

		CELD=document.getElementById("POND_"+MyITEM.Id);
		if (CELD)
		{
			var pond = GetNumber(CELD.value, this.PondDecimales);
			if (!isNaN(parseFloat(pond))) MyITEM.Pond=parseFloat(pond);
			CELD.value=FormatNumber(MyITEM.Pond, this.PondDecimales);
		}

		if (this.Evaluador =='2') 
		{
			CELD=document.getElementById("OE_"+MyITEM.Id); 
			if (CELD)
			{
				MyITEM.Value1=(CELD.value==""?null:parseFloat(CELD.value));
				if (MyITEM.Value1==null) this.OK=false;
			}
		}
		if (this.Evaluado  =='2') 
		{
			CELD=document.getElementById("OA_"+MyITEM.Id);
			if (CELD)
			{
				MyITEM.Value2=(CELD.value==""?null:parseFloat(CELD.value));
				if (MyITEM.Value2==null) this.OK=false;
			}
		}
		if (this.Supervisor=='2') 
		{
			CELD=document.getElementById("OS_"+MyITEM.Id);
			if (CELD)
			{
				MyITEM.Value3=(CELD.value==""?null:parseFloat(CELD.value));
				if (MyITEM.Value3==null) this.OK=false;
			}                           
		}                           


		//Totales      
		if (this.Value1==null || MyITEM.Value1==null) 
			this.Value1=null; 
		else 
		if (compare(MyITEM.Value1,0)!=-1)
		{
	    this.MaxValue1+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value1   +=MyITEM.Pond*MyITEM.Value1;
		}

		if (this.Value2==null || MyITEM.Value2==null) 
			this.Value2=null; 
		else 
		if (compare(MyITEM.Value2,0)!=-1)
		{
	    this.MaxValue2+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value2   +=MyITEM.Pond*MyITEM.Value2;
		}

		if (this.Value3==null || MyITEM.Value3==null) 
			this.Value3=null; 
		else 
		if (compare(MyITEM.Value3,0)!=-1)
		{
	    this.MaxValue3+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value3   +=MyITEM.Pond*MyITEM.Value3;
		}
	}

	if (!found)     
	{
		this.Value1=-1;
		this.Value2=-1;
		this.Value3=-1;      
	}

	if (this.Value1!=null) { this.Value1=(this.MaxValue1==0?-1:this.Value1/this.MaxValue1*ESCALAS.Get(this.Escala).max); }
	if (this.Value2!=null) { this.Value2=(this.MaxValue2==0?-1:this.Value2/this.MaxValue2*ESCALAS.Get(this.Escala).max); }
	if (this.Value3!=null) { this.Value3=(this.MaxValue3==0?-1:this.Value3/this.MaxValue3*ESCALAS.Get(this.Escala).max); }
}


