					//Cargo las Columnas Adicionales
PLA.EdtCols=new Array();
PLA.EvaCols=new Array();
var aux=PLA.Columnas.split(";");
for (t=0; t!=aux.length; t++)
{
	if (aux[t].substr(0,1)=="@")
	{
		PLA.EdtCols.push(aux[t].substr(1).split(":")[0]);
	} else                      
	if (aux[t].substr(0,1)=="$")
	{
		PLA.EvaCols.push(aux[t].substr(1).split(":")[0]);
	}
}    

var str="";
str ="function FormulaGenerica(arr){ try { var Pond=arr['Pond']; ";
for (t=0; t!=aux.length; t++)
{
	if ((aux[t].substr(0,1)=="@") || (aux[t].substr(0,1)=="$"))
	{
		str+="var "+aux[t].substr(1).split(":")[0]+"=arr['"+aux[t].substr(1).split(":")[0]+"'];";
	}
}    
str+="return "+PLA.Formula+";";
str+="} catch(e) { return null; } }";
eval(str);                           

PLA.Formula=FormulaGenerica;


function Extract(strIn, suf, arr)
{          
	if (strIn=="") return;

	var arrIn=strIn.split(";");
	var arrDt;
	var t;

	for (t=0; t!=arrIn.length; t++)
	if (arrIn[t]!="")
	{
		arrDt=arrIn[t].split("=");

		if (arrDt[1]=="N/A")
		{
			arr[suf+"_"+arrDt[0]]=-1;
		} else
		{
			arrDt[1]=parseFloat(arrDt[1]);
			if (isNaN(arrDt[1])) continue;

			arr[suf+"_"+arrDt[0]]=arrDt[1];
		}
	}
}                    

function Generate(Cols, Values, suf)
{
	var t,retval="";

	for(t=0; t!=Cols.length; t++)
	if (Values[suf+"_"+Cols[t]]!=null)
	retval+=Cols[t]+"="+FormatNumber(Values[suf+"_"+Cols[t]],3)+";";

	return retval;				
}


PLA.AddItem = function(MyItem)
{          
	var t;

	//Calculo Columnas Adicionales
	MyItem.Values=new Array();

	//Valores en 0 
	for (t=0; t!=this.EdtCols.length; t++) MyItem.Values["X_"+this.EdtCols[t]]=null;
	for (t=0; t!=this.EvaCols.length; t++) MyItem.Values["E_"+this.EvaCols[t]]=null;
	for (t=0; t!=this.EvaCols.length; t++) MyItem.Values["A_"+this.EvaCols[t]]=null;
	for (t=0; t!=this.EvaCols.length; t++) MyItem.Values["S_"+this.EvaCols[t]]=null;

	//Extraer Valores de CUS
	Extract(MyItem.Cus1, "X", MyItem.Values);
	Extract(MyItem.Cus2, "E", MyItem.Values);
	Extract(MyItem.Cus3, "A", MyItem.Values);
	Extract(MyItem.Cus4, "S", MyItem.Values);

	//Agrego el ITEM
	this.Items["K_"+MyItem.Id]=MyItem;
}       
PLA.RECALC = function()
{   
	if (this.Show!='1') return;

	var key, MyITEM, t, found=false, value, arrEval=new Array();

	this.Value1=0.0;
	this.Value2=0.0;
	this.Value3=0.0;
	this.MaxValue1=0.0;     
	this.MaxValue2=0.0;     
	this.MaxValue3=0.0;     
	this.OK=true;

	//Recorro los ITEMS
	for (key in this.Items)
	{
		MyITEM=this.Items[key];
		if (MyITEM.Delete) continue;
		found=true;

		CELD=document.getElementById("POND_"+MyITEM.Id);
		if (CELD)
		{
			var pond = GetNumber(CELD.value, this.PondDecimales);
			if (!isNaN(parseFloat(pond))) MyITEM.Pond=parseFloat(pond);
			CELD.value=FormatNumber(MyITEM.Pond, this.PondDecimales);
		}
		arrEval["Pond"]=MyITEM.Pond;

		//Generales
		for (t=0; t!=this.EdtCols.length; t++)
		{
			CELD=document.getElementById("OX_EDT_"+this.EdtCols[t]+"_"+MyITEM.Id);
			if (CELD)
			{
				if (CELD.value=="") 
					MyITEM.Values["X_"+this.EdtCols[t]]=null;
				else                                 
				{                              
					value=GetNumber(CELD.value, this.Decimales);
					if (CELD.value!="@") if (!isNaN(parseFloat(value))) MyITEM.Values["X_"+this.EdtCols[t]]=parseFloat(value);
					CELD.value=FormatNumber(MyITEM.Values["X_"+this.EdtCols[t]], this.Decimales); 
				}                                                                             
			} else
			{
				CELD=document.getElementById("DIV_OX_EDT_"+this.EdtCols[t]+"_"+MyITEM.Id);
				CELD.innerHTML=FormatNumber(MyITEM.Values["X_"+this.EdtCols[t]], this.Decimales); 
			}

			//Valores Comunes
			arrEval[this.EdtCols[t]]=MyITEM.Values["X_"+this.EdtCols[t]];
		}


		if (this.Evaluador !='0') 
		{
			for (t=0; t!=this.EvaCols.length; t++)
			{
				CELD=document.getElementById("OX_EVA_"+this.EvaCols[t]+"_"+MyITEM.Id);
				if (CELD)
				{
					if (CELD.value=="") 
						MyITEM.Values["E_"+this.EvaCols[t]]=null;
					else                                 
					{                              
						value=GetNumber(CELD.value, this.Decimales);
						if (CELD.value!="@") MyITEM.Values["E_"+this.EvaCols[t]]=value;
						CELD.value=FormatNumber(MyITEM.Values["E_"+this.EvaCols[t]], this.Decimales); 
					}
				} else
				{ 
					CELD=document.getElementById("DIV_OX_EVA_"+this.EvaCols[t]+"_"+MyITEM.Id);     
					CELD.innerHTML=FormatNumber(MyITEM.Values["E_"+this.EvaCols[t]], this.Decimales); 
				}
				//Valores Comunes
				arrEval[this.EvaCols[t]]=MyITEM.Values["E_"+this.EvaCols[t]];
			}

			value=this.Formula(arrEval);
			if (isNaN(value)) value=null;
			MyITEM.Value1=value;

			CELD=document.getElementById("DIV_OE_"+MyITEM.Id); 
			if (MyITEM.Value1==null)
			{
				CELD.innerHTML="";
			} else
			{
				if (compare(MyITEM.Value1,ESCALAS.Get(MyITEM.Escala).max)== 1)
				MyITEM.Value1=ESCALAS.Get(MyITEM.Escala).max;

				if (compare(MyITEM.Value1,ESCALAS.Get(MyITEM.Escala).min)==-1)
				MyITEM.Value1=ESCALAS.Get(MyITEM.Escala).min;

				if (compare(MyITEM.Value1,0)==-1)
					MyITEM.Value1=-1;

				CELD.innerHTML=FormatTotal(MyITEM.Escala, MyITEM.Value1, this.Decimales);
			}
		}        

		if (this.Evaluado !='0') 
		{
			for (t=0; t!=this.EvaCols.length; t++)
			{
				CELD=document.getElementById("OX_AUT_"+this.EvaCols[t]+"_"+MyITEM.Id);
				if (CELD)
				{
					if (CELD.value=="") 
						MyITEM.Values["A_"+this.EvaCols[t]]=null;
					else                                 
					{                              
						value=GetNumber(CELD.value, this.Decimales);
						if (CELD.value!="@") MyITEM.Values["A_"+this.EvaCols[t]]=value;
						CELD.value=FormatNumber(MyITEM.Values["A_"+this.EvaCols[t]], this.Decimales); 
					}
				} else
				{
					CELD=document.getElementById("DIV_OX_AUT_"+this.EvaCols[t]+"_"+MyITEM.Id);
					CELD.innerHTML=FormatNumber(MyITEM.Values["A_"+this.EvaCols[t]], this.Decimales); 
				}
				//Valores Comunes
				arrEval[this.EvaCols[t]]=MyITEM.Values["A_"+this.EvaCols[t]];
			}
			value=this.Formula(arrEval);
			if (isNaN(value)) value=null;
			MyITEM.Value2=value;

