				{
					if (CELD.value=="") 
						MyITEM.Values["S_"+this.EvaCols[t]]=null;
					else                                 
					{                              
						value=GetNumber(CELD.value, this.Decimales);
						if (CELD.value!="@") MyITEM.Values["S_"+this.EvaCols[t]]=value;
						CELD.value=FormatNumber(MyITEM.Values["S_"+this.EvaCols[t]], this.Decimales); 
					}
				} else
				{
					CELD=document.getElementById("DIV_OX_SUP_"+this.EvaCols[t]+"_"+MyITEM.Id);
					CELD.innerHTML=FormatNumber(MyITEM.Values["S_"+this.EvaCols[t]], this.Decimales); 
				}
				//Valores Comunes
				arrEval[this.EvaCols[t]]=MyITEM.Values["S_"+this.EvaCols[t]];
			}
			value=this.Formula(arrEval);
			if (isNaN(value)) value=null;
			MyITEM.Value3=value;

			CELD=document.getElementById("DIV_OS_"+MyITEM.Id); 
			if (MyITEM.Value3==null)
			{
				CELD.innerHTML="";
			} else
			{
				if (compare(MyITEM.Value3,ESCALAS.Get(MyITEM.Escala).max)== 1)
				MyITEM.Value3=ESCALAS.Get(MyITEM.Escala).max;

				if (compare(MyITEM.Value3,ESCALAS.Get(MyITEM.Escala).min)==-1)
				MyITEM.Value3=ESCALAS.Get(MyITEM.Escala).min;

				if (compare(MyITEM.Value3,0)==-1)
					MyITEM.Value3=-1;

				CELD.innerHTML=FormatTotal(MyITEM.Escala, MyITEM.Value3, this.Decimales);
			}
		}                           

		//Totales      
		if (this.Value1==null || MyITEM.Value1==null) 
			this.Value1=null; 
		else 
		if (compare(MyITEM.Value1,0)!=-1)
		{
	    this.MaxValue1+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value1   +=MyITEM.Pond*MyITEM.Value1;
		}

		if (this.Value2==null || MyITEM.Value2==null) 
			this.Value2=null; 
		else 
		if (compare(MyITEM.Value2,0)!=-1)
		{
	    this.MaxValue2+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value2   +=MyITEM.Pond*MyITEM.Value2;
		}

		if (this.Value3==null || MyITEM.Value3==null) 
			this.Value3=null; 
		else 
		if (compare(MyITEM.Value3,0)!=-1)
		{
	    this.MaxValue3+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value3   +=MyITEM.Pond*MyITEM.Value3;
		}

	}

	if (!found)     
	{
		this.Value1=-1;
		this.Value2=-1;
		this.Value3=-1;      
	}

	if (this.Value1!=null) { this.Value1=(this.MaxValue1==0?-1:this.Value1/this.MaxValue1*ESCALAS.Get(this.Escala).max); }
	if (this.Value2!=null) { this.Value2=(this.MaxValue2==0?-1:this.Value2/this.MaxValue2*ESCALAS.Get(this.Escala).max); }
	if (this.Value3!=null) { this.Value3=(this.MaxValue3==0?-1:this.Value3/this.MaxValue3*ESCALAS.Get(this.Escala).max); }
}

PLA.DDOCHANGE_ADIC = function(DDOEVA, DDOPLA)
{
	var key, MyITEM, DDOITEM, COMENT;

	var MaxID=0;
	for (DDOITEM=DDOPLA.FindElement("OBJETIVOS").FirstChild(); DDOITEM!=null; DDOITEM=DDOITEM.Next())
	if	(!isNaN(DDOITEM.GetAttrInt("c_objetivo"))) 
	if	(compare(DDOITEM.GetAttrInt("c_objetivo"),MaxID)==1) 
	MaxID=DDOITEM.GetAttrInt("c_objetivo");

	for (key in this.Items)
	{                      
		MyITEM=this.Items[key];          

		//Calculo de CUS
		MyITEM.Cus1=Generate(this.EdtCols,MyITEM.Values,"X");
		MyITEM.Cus2=Generate(this.EvaCols,MyITEM.Values,"E");
		MyITEM.Cus3=Generate(this.EvaCols,MyITEM.Values,"A");
		MyITEM.Cus4=Generate(this.EvaCols,MyITEM.Values,"S");

 		if (MyITEM.New)
 		{                              
 			if (MyITEM.Delete) continue;
 			CheckSize("OBJETIVO",1000,document.getElementById("MSG_"+MyITEM.Id));

 			MaxID++;
			DDOITEM=DDOPLA.FindElement("OBJETIVOS").AddTailElement("OBJETIVO");
			DDOITEM.SetAttr("nmd-status"   , "~i,");							
			DDOITEM.SetAttr("id"           , "~"+MyITEM.Id);
			DDOITEM.SetAttr("c_objetivo"   , MaxID);
			DDOITEM.SetAttr("d_objetivo"   , document.getElementById("MSG_"+MyITEM.Id).value);
			DDOITEM.SetAttr("n_ponderacion", MyITEM.Pond);
			DDOITEM.SetAttr("d_cus1", MyITEM.Cus1);
			DDOITEM.SetAttr("d_cus2", MyITEM.Cus2);
			DDOITEM.SetAttr("d_cus3", MyITEM.Cus3);
			DDOITEM.SetAttr("d_cus4", MyITEM.Cus4);
			if (this.Evaluador =="2") DDOITEM.SetAttr("n_resultado"  , MyITEM.Value1==null?"":MyITEM.Value1);
			if (this.Evaluado  =="2") DDOITEM.SetAttr("n_resultado2" , MyITEM.Value2==null?"":MyITEM.Value2); 
			if (this.Supervisor=="2") DDOITEM.SetAttr("n_resultado3" , MyITEM.Value3==null?"":MyITEM.Value3);  
			DDOITEM.AddTailElement("oi_competencia");
			DDOITEM.AddTailElement("oi_escala");
 		} else             
 		if (MyITEM.Delete)
 		{
			DDOITEM=DDOPLA.FindElement("OBJETIVOS").FindElement2("OBJETIVO","ID",MyITEM.Id);
			DDOITEM.SetAttr("nmd-status" , "~d,");
 		} else
 		{
			DDOITEM=DDOPLA.FindElement("OBJETIVOS").FindElement2("OBJETIVO","ID",MyITEM.Id);
			DDOITEM.SetAttr("nmd-status" , "~u,");							 
			if (document.getElementById("MSG_"+MyITEM.Id))
			{
				CheckSize("OBJETIVO",1000,document.getElementById("MSG_"+MyITEM.Id));
				DDOITEM.SetAttr("d_objetivo"   , document.getElementById("MSG_"+MyITEM.Id).value);
			}
			DDOITEM.SetAttr("n_ponderacion", MyITEM.Pond);
			DDOITEM.SetAttr("d_cus1", MyITEM.Cus1);
			DDOITEM.SetAttr("d_cus2", MyITEM.Cus2);
			DDOITEM.SetAttr("d_cus3", MyITEM.Cus3);
			DDOITEM.SetAttr("d_cus4", MyITEM.Cus4);
			if (this.Evaluador =="2") { DDOITEM.SetAttr("n_resultado"  , MyITEM.Value1==null?"":MyITEM.Value1); }
			if (this.Evaluado  =="2") { DDOITEM.SetAttr("n_resultado2" , MyITEM.Value2==null?"":MyITEM.Value2); } 
			if (this.Supervisor=="2") { DDOITEM.SetAttr("n_resultado3" , MyITEM.Value3==null?"":MyITEM.Value3); }  
 		}
	}
}

