	 			DDOITEM.SetAttr("nmd-status"  , "~d,");
	 		} else
	 		{
				DDOITEM=DDOPLA.FindElement("OBJETIVOS").FindElement2("OBJETIVO","ID",MyITEM.Id);
				DDOITEM.SetAttr("nmd-status"  , "~u,");							
				CELD=document.getElementById("MSG_"+MyITEM.Id+"_1"); if (CELD) { CheckSize("CUS",1000,CELD); DDOITEM.SetAttr("d_cus1", CELD.value); }
				CELD=document.getElementById("MSG_"+MyITEM.Id+"_2"); if (CELD) { CheckSize("CUS",1000,CELD); DDOITEM.SetAttr("d_cus2", CELD.value); }
				CELD=document.getElementById("MSG_"+MyITEM.Id+"_3"); if (CELD) { CheckSize("CUS",1000,CELD); DDOITEM.SetAttr("d_cus3", CELD.value); }
				CELD=document.getElementById("MSG_"+MyITEM.Id+"_4"); if (CELD) { CheckSize("CUS",1000,CELD); DDOITEM.SetAttr("d_cus4", CELD.value); }
				CELD=document.getElementById("MSG_"+MyITEM.Id+"_5"); if (CELD) { CheckSize("CUS",1000,CELD); DDOITEM.SetAttr("d_cus5", CELD.value); }
				DDOITEM.SetAttr("n_resultado" , "");
