xsl:for-each.xsl:text:
						ITEM.CtrlList=null;
ITEM.CtrlList2=null;
ITEM.CtrlList3=null;
ITEM.Value=null;
ITEM.Value2=null;
ITEM.Value3=null;
ITEM.New=false;
ITEM.Delete=false;
