script.xsl:text:
					PLA.DDOCHANGE_ADIC = function(DDOEVA, DDOPLA)
{    
	var COMENT;

	//Comentarios de la Plantilla
	if (this.Evaluador360=='3')
	{
		COMENT=document.getElementById("COMENT_"+this.Id+"_"+EVALUADORES.oi_evaluador_360);
		if (COMENT)
		{              
			CheckSize("COMENT",4000,COMENT);                  


			//Busco evaluador
			DDO360=null;
			for (CUR=DDOPLA.FindElement("EVALUADORES").FirstChild(); CUR!=null; CUR=CUR.Next())
				if (CUR.FindElement("oi_personal_emp").GetAttr("value")==EVALUADORES.oi_evaluador_360)
				{
					DDO360=CUR;
					break;
				}

			if (DDO360==null)
			{
				DDO360=DDOPLA.FindElement("EVALUADORES").AddTailElement("PLA_EVALUADOR");
				DDO360.SetAttr("nmd-status"   , "~i,");
				DDO360.SetAttr("id"           , "~C_XXX");
				DDO360.AddTailElement("oi_personal_emp").SetAttr("value", EVALUADORES.oi_evaluador_360);
			} else
			{                                       
				DDO360.SetAttr("nmd-status"   , "~u,");
			}
			DDO360.SetAttr("o_comentario", COMENT.value);
		}
	}
}

					PLA.REFRESH = function()
{ 
	var key, key2, MyPLA, MaxValue1, MaxValue2, MaxValue3, MyOBJ1, MyOBJ2;

	//Inicializo los Contadores                         
  MaxValue1=0.0; Value1=0.0;
  MaxValue2=0.0; Value2=0.0;
  MaxValue3=0.0; Value3=0.0;
  MaxValues=new Array(); Values=new Array();
  for (key2 in EVALUADORES.items) { MaxValues[key2]=0.0; Values[key2]=0.0; }
	escEvaMax=ESCALAS.Get(EVA.Escala).max;


	//Recorro las Plantillas y Actualizo la Columna
	for(key in EVA.Plantillas)
	{                 
		MyPLA=EVA.Plantillas[key];
		if (!MyPLA.MostrarResumen) continue;

		escMax=ESCALAS.Get(MyPLA.Escala).max;

		MyPLA.ProValue1=null;
		MyPLA.ProValue2=null;
		MyPLA.ProValue3=null; 

		if (MyPLA.Sum360==1)             
		{
			MyPLA.ProValues=new Array();
		  for (key2 in EVALUADORES.items) 
		  	MyPLA.ProValues[key2]=null;
	  }


		if (MyPLA.SumEva==1)
		{
			if (isNaN(MyPLA.Value1) || MyPLA.Value1==null)    
			{
				Value1=null;
				MyPLA.ProValue1=null;
			} else
			if (compare(MyPLA.Value1,0)!=-1)
			{
				MyPLA.ProValue1 =MyPLA.Pond * MyPLA.Value1 / escMax;
				MaxValue1      +=MyPLA.Pond;
				if (Value1!=null) Value1+=MyPLA.ProValue1;
			} else
				MyPLA.ProValue1=-1;

		}

		if (MyPLA.SumAut==1)
		{
			if (isNaN(MyPLA.Value2) || MyPLA.Value2==null)    
			{
				Value2=null;
				MyPLA.ProValue2=null;
			} else
			if (compare(MyPLA.Value2,0)!=-1)
			{
				MyPLA.ProValue2 =MyPLA.Pond * MyPLA.Value2 / escMax;
				MaxValue2      +=MyPLA.Pond;
				if (Value2!=null) Value2+=MyPLA.ProValue2;
			} else
				MyPLA.ProValue2=-1;
		}

		if (MyPLA.SumSup==1)
		{
			if (isNaN(MyPLA.Value3) || MyPLA.Value3==null)    
			{
				Value3=null;
				MyPLA.ProValue3=null;
			} else
			if (compare(MyPLA.Value3,0)!=-1)
			{
				MyPLA.ProValue3 =MyPLA.Pond *  MyPLA.Value3 / escMax;
				MaxValue3      +=MyPLA.Pond;
				if (Value3!=null) Value3+=MyPLA.ProValue3;
			} else
				MyPLA.ProValue3=-1;
		}

		if (MyPLA.Sum360==1)
		{                   
			for (key2 in EVALUADORES.items) 
			{ 
				if (isNaN(MyPLA.Values[key2]) || MyPLA.Values[key2]==null)    
				{
					Values[key2]=null;
					MyPLA.ProValues[key2]=null;
				} else
				if (compare(MyPLA.Values[key2],0)!=-1)
				{
					MyPLA.ProValues[key2] =MyPLA.Pond * MyPLA.Values[key2] / escMax;
					MaxValues[key2]      +=MyPLA.Pond;
					if (Values[key2]!=null) Values[key2]+=MyPLA.ProValues[key2];
				} else
					MyPLA.ProValues[key2]=-1;
			}
		}

	}


	//Recorro las Plantillas y Actualizo la Columna
	for(key in EVA.Plantillas)
	{                 
		MyPLA=EVA.Plantillas[key];
		if (!MyPLA.MostrarResumen) continue;

		escMax=ESCALAS.Get(MyPLA.Escala).max;

		MyOBJ1=document.getElementById("PE_"+this.Id+"_"+MyPLA.Id); 
		MyOBJ2=document.getElementById("PES_"+this.Id+"_"+MyPLA.Id);

		if (MyOBJ1) 
		if (MyOBJ2)
		{
			if (MyPLA.SumEva==1)
			{
				MyOBJ1.innerHTML=FormatTotal(MyPLA.Escala, MyPLA.Value1, MyPLA.Decimales?MyPLA.Decimales:0);
				MyOBJ2.innerHTML=FormatNumber(MyPLA.ProValue1 / MaxValue1 * escEvaMax, this.Decimales?this.Decimales:0);
			} else
			{
				MyOBJ1.innerHTML="-";
				MyOBJ2.innerHTML="-";
			}
		}               


		MyOBJ1=document.getElementById("PA_"+this.Id+"_"+MyPLA.Id); 
		MyOBJ2=document.getElementById("PAS_"+this.Id+"_"+MyPLA.Id);

		if (MyOBJ1) 
		if (MyOBJ2)
		{
			if (MyPLA.SumAut==1)
			{
				MyOBJ1.innerHTML=FormatTotal(MyPLA.Escala, MyPLA.Value2, MyPLA.Decimales?MyPLA.Decimales:0);
				MyOBJ2.innerHTML=FormatNumber(MyPLA.ProValue2 / MaxValue2 * escEvaMax, this.Decimales?this.Decimales:0);
			} else
			{
				MyOBJ1.innerHTML="-";
				MyOBJ2.innerHTML="-";
			}
		}       


		MyOBJ1=document.getElementById("PS_"+this.Id+"_"+MyPLA.Id); 
		MyOBJ2=document.getElementById("PSS_"+this.Id+"_"+MyPLA.Id);
		if (MyOBJ1) 
		if (MyOBJ2)
		{
			if (MyPLA.SumSup==1)
			{
				MyOBJ1.innerHTML=FormatTotal(MyPLA.Escala, MyPLA.Value3, MyPLA.Decimales?MyPLA.Decimales:0);
				MyOBJ2.innerHTML=FormatNumber(MyPLA.ProValue3 / MaxValue3 * escEvaMax, this.Decimales?this.Decimales:0);
			} else
			{
				MyOBJ1.innerHTML="-";
				MyOBJ2.innerHTML="-";
			}
		}   

		for (key2 in EVALUADORES.items) 
		{ 
			MyOBJ1=document.getElementById("P3_"+this.Id+"_"+MyPLA.Id+"_"+key2.substr(1)); 
			MyOBJ2=document.getElementById("P3S_"+this.Id+"_"+MyPLA.Id+"_"+key2.substr(1));
			if (MyOBJ1) 
			if (MyOBJ2)
			{                
				if (MyPLA.Sum360==1)
				{                   
					MyOBJ1.innerHTML=FormatTotal(MyPLA.Escala, MyPLA.Values[key2], MyPLA.Decimales?MyPLA.Decimales:0);
					MyOBJ2.innerHTML=FormatNumber(MyPLA.ProValues[key2] / MaxValues[key2] * escEvaMax , this.Decimales?this.Decimales:0);
				} else
				{
					MyOBJ1.innerHTML="-";
					MyOBJ2.innerHTML="-";
				} 
			}   
		}


	} 


	//Verifico Totales
  if (MaxValue1==0.0) Value1=-1;
  if (MaxValue2==0.0) Value2=-1;
  if (MaxValue3==0.0) Value3=-1;
  for (key2 in EVALUADORES.items) if (MaxValues[key2]==0.0) { Values[key2]=-1; }

 	//Calculo Totales
	if (Value1!=null) if (compare(Value1,0)!=-1) Value1 = Value1 / MaxValue1 * escEvaMax;
	if (Value2!=null) if (compare(Value2,0)!=-1) Value2 = Value2 / MaxValue2 * escEvaMax;
	if (Value3!=null) if (compare(Value3,0)!=-1) Value3 = Value3 / MaxValue3 * escEvaMax;
	for (key2 in EVALUADORES.items) 
	{
		if (Values[key2]!=null) if (compare(Values[key2],0)!=-1) Values[key2] = Values[key2] / MaxValues[key2] * escEvaMax;
	}

	//Totales
	MyOBJ1=document.getElementById("TRE_"+this.Id); if (MyOBJ1) MyOBJ1.innerHTML=FormatTotal(EVA.Escala, Value1, this.Decimales?this.Decimales:0);
	MyOBJ1=document.getElementById("TRA_"+this.Id); if (MyOBJ1) MyOBJ1.innerHTML=FormatTotal(EVA.Escala, Value2, this.Decimales?this.Decimales:0);
	MyOBJ1=document.getElementById("TRS_"+this.Id); if (MyOBJ1) MyOBJ1.innerHTML=FormatTotal(EVA.Escala, Value3, this.Decimales?this.Decimales:0);
	for (key2 in EVALUADORES.items) 
	{                                              
		MyOBJ1=document.getElementById("TR3_"+this.Id+"_"+key2.substr(1));
		if (MyOBJ1) MyOBJ1.innerHTML=FormatTotal(EVA.Escala, Values[key2], this.Decimales?this.Decimales:0);
	}
}

					PLA.RECALC = function()
{    
	if (this.Show!='1') return;

	var key, MyITEM, MySUBITEM, t, found=false, subfound;   

	this.Value1=0.0;
	this.Value2=0.0;
	this.Value3=0.0;
	this.Values["K"+EVALUADORES.oi_evaluador_360]=0.0;

	this.MaxValue1=0.0;
	this.MaxValue2=0.0;
	this.MaxValue3=0.0;
	this.MaxValueX=0.0;
	this.OK=true;

	//Recorro los ITEMS
	for (key in this.Items)
	{
		MyITEM=this.Items[key];
		if (MyITEM.Delete) continue;
		found=true; subfound=false;

		//	                 
		MyITEM.Value1=0.0;
		MyITEM.Value2=0.0;
		MyITEM.Value3=0.0;      
		MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]=0.0;

		MyITEM.MaxValue1=0;
		MyITEM.MaxValue2=0;
		MyITEM.MaxValue3=0;
		MyITEM.MaxValueX=0;

		for (key2 in MyITEM.Subitems)
		{                         
			MySUBITEM=MyITEM.Subitems[key2];
			if (MySUBITEM.Delete) continue;
			subfound=true;

			if (this.Evaluador =='2') 
			{
				CELD=document.getElementById("OE_"+MyITEM.Id+"_"+MySUBITEM.Id);
				if (CELD)
				{
					MySUBITEM.Value1=(CELD.value==""?null:parseFloat(CELD.value));
					if (MySUBITEM.Value1==null) this.OK=false;
				}
			}              

			if (this.Evaluado  =='2') 
			{
				CELD=document.getElementById("OA_"+MyITEM.Id+"_"+MySUBITEM.Id);
				if (CELD)
				{
					MySUBITEM.Value2=(CELD.value==""?null:parseFloat(CELD.value));
					if (MySUBITEM.Value2==null) this.OK=false;
				}
			}

			if (this.Supervisor=='2') 
			{
				CELD=document.getElementById("OS_"+MyITEM.Id+"_"+MySUBITEM.Id);
				if (CELD)
				{
					MySUBITEM.Value3=(CELD.value==""?null:parseFloat(CELD.value));
					if (MySUBITEM.Value3==null) this.OK=false;
				}                           
			}                           

			if (this.Evaluador360=='3')
			{                      
				CELD=document.getElementById("O3_"+MyITEM.Id+"_"+MySUBITEM.Id+"_"+EVALUADORES.oi_evaluador_360);
				if (CELD)
				{
					MySUBITEM.Values["K"+EVALUADORES.oi_evaluador_360]=(CELD.value==""?null:parseFloat(CELD.value));
					if (MySUBITEM.Values["K"+EVALUADORES.oi_evaluador_360]==null) this.OK=false;
				} 
			}                    

			//Totales      
			if (MyITEM.Value1==null || MySUBITEM.Value1==null) 
				MyITEM.Value1=null; 
			else 
			if (compare(MySUBITEM.Value1,0)!=-1)
			{
		    MyITEM.MaxValue1+=MySUBITEM.Pond*ESCALAS.Get(MySUBITEM.Escala).max;
				MyITEM.Value1   +=MySUBITEM.Pond*MySUBITEM.Value1;
			}

			if (MyITEM.Value2==null || MySUBITEM.Value2==null) 
				MyITEM.Value2=null; 
			else 
			if (compare(MySUBITEM.Value2,0)!=-1)
			{
		    MyITEM.MaxValue2+=MySUBITEM.Pond*ESCALAS.Get(MySUBITEM.Escala).max;
				MyITEM.Value2   +=MySUBITEM.Pond*MySUBITEM.Value2;
			}

			if (MyITEM.Value3==null || MySUBITEM.Value3==null) 
				MyITEM.Value3=null; 
			else 
			if (compare(MySUBITEM.Value3,0)!=-1)
			{
		    MyITEM.MaxValue3+=MySUBITEM.Pond*ESCALAS.Get(MySUBITEM.Escala).max;
				MyITEM.Value3   +=MySUBITEM.Pond*MySUBITEM.Value3;
			}

			if (MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]==null || MySUBITEM.Values["K"+EVALUADORES.oi_evaluador_360]==null) 
				MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]=null; 
			else 
			if (compare(MySUBITEM.Values["K"+EVALUADORES.oi_evaluador_360],0)!=-1)
			{
		    MyITEM.MaxValueX+=MySUBITEM.Pond*ESCALAS.Get(MySUBITEM.Escala).max;
				MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]+=MySUBITEM.Pond*MySUBITEM.Values["K"+EVALUADORES.oi_evaluador_360];
			}
		}

		if (!subfound)     
		{
			MyITEM.Value1=-1;
			MyITEM.Value2=-1;
			MyITEM.Value3=-1;
			MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]=-1;      
		}

		if (MyITEM.Value1!=null) { MyITEM.Value1=(MyITEM.MaxValue1==0?-1:MyITEM.Value1/MyITEM.MaxValue1*ESCALAS.Get(MyITEM.Escala).max); }
		if (MyITEM.Value2!=null) { MyITEM.Value2=(MyITEM.MaxValue2==0?-1:MyITEM.Value2/MyITEM.MaxValue2*ESCALAS.Get(MyITEM.Escala).max); }
		if (MyITEM.Value3!=null) { MyITEM.Value3=(MyITEM.MaxValue3==0?-1:MyITEM.Value3/MyITEM.MaxValue3*ESCALAS.Get(MyITEM.Escala).max); }
		if (MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]!=null) { MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]=(MyITEM.MaxValueX==0?-1:MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]/MyITEM.MaxValueX*ESCALAS.Get(MyITEM.Escala).max); }


		//Totales      
		if (this.Value1==null || MyITEM.Value1==null) 
			this.Value1=null; 
		else 
		if (compare(MyITEM.Value1,0)!=-1)
		{
	    this.MaxValue1+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value1   +=MyITEM.Pond*MyITEM.Value1;
		}

		if (this.Value2==null || MyITEM.Value2==null) 
			this.Value2=null; 
		else 
		if (compare(MyITEM.Value2,0)!=-1)
		{
	    this.MaxValue2+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value2   +=MyITEM.Pond*MyITEM.Value2;
		}

		if (this.Value3==null || MyITEM.Value3==null) 
			this.Value3=null; 
		else 
		if (compare(MyITEM.Value3,0)!=-1)
		{
	    this.MaxValue3+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Value3   +=MyITEM.Pond*MyITEM.Value3;
		}

		if (this.Values["K"+EVALUADORES.oi_evaluador_360]==null || MyITEM.Values["K"+EVALUADORES.oi_evaluador_360]==null) 
			this.Values["K"+EVALUADORES.oi_evaluador_360]=null; 
		else 
		if (compare(MyITEM.Values["K"+EVALUADORES.oi_evaluador_360],0)!=-1)
		{
	    this.MaxValueX+=MyITEM.Pond*ESCALAS.Get(MyITEM.Escala).max;
			this.Values["K"+EVALUADORES.oi_evaluador_360]+=MyITEM.Pond*MyITEM.Values["K"+EVALUADORES.oi_evaluador_360];
		}
	}

	if (!found)     
	{
		this.Value1=-1;
		this.Value2=-1;
		this.Value3=-1;
		this.Values["K"+EVALUADORES.oi_evaluador_360]=-1;
	}

	if (this.Value1!=null) { this.Value1=(this.MaxValue1==0?-1:this.Value1/this.MaxValue1*ESCALAS.Get(this.Escala).max); }
	if (this.Value2!=null) { this.Value2=(this.MaxValue2==0?-1:this.Value2/this.MaxValue2*ESCALAS.Get(this.Escala).max); }
	if (this.Value3!=null) { this.Value3=(this.MaxValue3==0?-1:this.Value3/this.MaxValue3*ESCALAS.Get(this.Escala).max); }
	if (this.Values["K"+EVALUADORES.oi_evaluador_360]!=null) { this.Values["K"+EVALUADORES.oi_evaluador_360]=(this.MaxValueX==0?-1:this.Values["K"+EVALUADORES.oi_evaluador_360]/this.MaxValueX*ESCALAS.Get(this.Escala).max); }
}


PLA.DDOCHANGE_ADIC = function(DDOEVA, DDOPLA)
{
	var key, key2, MyITEM, MySUBITEM, DDOITEM, DDOSUBITEM, DDO360, COMENT;

	if (this.Evaluador360=='3')
	{ //Evaluacion 360

		//Busco evaluador
		DDO360=null;
		for (CUR=DDOPLA.FindElement("EVALUADORES").FirstChild(); CUR!=null; CUR=CUR.Next())
			if (CUR.FindElement("oi_personal_emp").GetAttr("value")==EVALUADORES.oi_evaluador_360)
			{
				DDO360=CUR;
				break;
			}

		if (DDO360==null)
		{
			DDO360=DDOPLA.FindElement("EVALUADORES").AddTailElement("PLA_EVALUADOR");
